package genxsolution.vms.vmsbackend.vehicle_management.vehicle_daily_activity.controller;
import genxsolution.vms.vmsbackend.common.query.ListQueryEngine; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_daily_activity.dto.*; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_daily_activity.service.VehicleDailyActivityService; import org.springframework.http.HttpStatus; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/v1/vehicles/daily-activities") public class VehicleDailyActivityController { private final VehicleDailyActivityService service; public VehicleDailyActivityController(VehicleDailyActivityService service){this.service=service;} @GetMapping public List<VehicleDailyActivityResponse> list(@RequestParam(required=false) UUID companyId,@RequestParam Map<String,String> filters){ return ListQueryEngine.apply(service.list(companyId), filters, Set.of("companyId")); } @GetMapping("/{id}") public VehicleDailyActivityResponse getById(@PathVariable UUID id){ return service.getById(id);} @PostMapping @ResponseStatus(HttpStatus.CREATED) public VehicleDailyActivityResponse create(@RequestBody VehicleDailyActivityUpsertRequest r){ return service.create(r);} @PutMapping("/{id}") public VehicleDailyActivityResponse update(@PathVariable UUID id,@RequestBody VehicleDailyActivityUpsertRequest r){ return service.update(id,r);} @DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@PathVariable UUID id){ service.delete(id);} }
